Bash(powershell.exe -Command "
\\$folders = @\(
  @{N='Docker Data';P=\\"\\$env:LOCALAPPDATA\\\\Docker\\"},
  @{N='Docker WSL';P=\\"\\$env:LOCALAPPDATA\\\\Docker\\\\wsl\\"},
  @{N='npm cache';P=\\"\\$env:APPDATA\\\\npm-cache\\"},
  @{N='Temp';P=\\"\\$env:TEMP\\"},
  @{N='Windows Temp';P='C:\\\\Windows\\\\Temp'},
  @{N='VPN node_modules';P='C:\\\\Users\\\\123\\\\Desktop\\\\vpn\\\\app\\\\node_modules'},
  @{N='Recycle Bin';P='C:\\\\\\$Recycle.Bin'}
\)
foreach \(\\$f in \\$folders\) {
  if \(Test-Path \\$f.P\) {
    \\$size = \(Get-ChildItem -Path \\$f.P -Recurse -Force -ErrorAction SilentlyContinue | Measure-Object -Property Length -Sum -ErrorAction SilentlyContinue\).Sum
    Write-Output \('{0}: {1:N1} GB' -f \\$f.N, \(\\$size/1GB\)\)
  }
}" 2>&1)
